package com.example.oauth2client;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.util.UriComponentsBuilder;

@Controller
@RequestMapping("/oauth2")
public class OAuth2ClientController {

    @Value("${spring.security.oauth2.client.registration.auth-server-url}")
    private String authServerUrl;

    @Value("${spring.security.oauth2.client.registration.client-id}")
    private String clientId;

    @Value("${spring.security.oauth2.client.registration.redirect-uri}")
    private String redirectUri;

    @Value("${spring.security.oauth2.client.registration.scope}")
    private String scope;

    @GetMapping("/login")
    public String redirectToAuthorizationServer() {
        String authorizationUrl = UriComponentsBuilder.fromHttpUrl(authServerUrl)
                .queryParam("client_id", clientId)
                .queryParam("redirect_uri", redirectUri)
                .queryParam("scope", scope)
                .queryParam("response_type", "code")
                .toUriString();
        
        return "redirect:" + authorizationUrl;
    }
}